import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.B45ElpZ1.js";const g=JSON.parse(`{"title":"Personas & Modes","description":"Overview of tradecli's Learner, Investor, Trader, Hedge Fund, and PMS workflows. How to pick one, and what switching means.","frontmatter":{"title":"Personas & Modes","description":"Overview of tradecli's Learner, Investor, Trader, Hedge Fund, and PMS workflows. How to pick one, and what switching means.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/personas"}]]},"headers":[],"relativePath":"guides/personas.md","filePath":"guides/personas.md"}`),s={name:"guides/personas.md"};function n(i,e,d,l,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="personas-modes" tabindex="-1">Personas &amp; Modes <a class="header-anchor" href="#personas-modes" aria-label="Permalink to &quot;Personas &amp; Modes&quot;">​</a></h1><p><code>tradecli</code> has specialist workflows for learning, investing, trading, and multi-agent office work. Investor and Trader are the primary single-agent work modes. Hedge Fund and PMS are Office Mode desks where a CEO pane coordinates specialist workers.</p><p>Modes are chosen from the same picker (<code>Ctrl+\\</code> inside the TUI). Each keeps its own session state, so switching away and back doesn&#39;t lose your place.</p><div class="tip custom-block"><p class="custom-block-title">Why separate?</p><p>A trader sizing a 5-minute setup, an investor writing a 10-year thesis, and an office desk coordinating portfolio context need different tools and different defaults. Separating them keeps the prompt focused and the tool palette clean.</p></div><h2 id="picking-one" tabindex="-1">Picking one <a class="header-anchor" href="#picking-one" aria-label="Permalink to &quot;Picking one&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You want to…</th><th>Use</th></tr></thead><tbody><tr><td>Learn trading or investing from scratch</td><td><a href="/wiki/guides/learner"><strong>Learner mode</strong></a></td></tr><tr><td>Research a listed Indian company or find ideas</td><td><a href="/wiki/guides/investor"><strong>Investor</strong></a></td></tr><tr><td>Build, backtest, and deploy a Streak strategy</td><td><a href="/wiki/guides/trader"><strong>Trader</strong></a></td></tr><tr><td>Coordinate investor and trader workers around one thesis</td><td><strong>Hedge Fund Office Mode</strong></td></tr><tr><td>Review model portfolios, mandates, concentration, and client context</td><td><a href="/wiki/guides/portfolio-manager"><strong>PMS and portfolio workflows</strong></a></td></tr></tbody></table><p>If you&#39;re unsure, start with <a href="/wiki/guides/learner">Learner</a> — it introduces the vocabulary and the platforms. You can switch later.</p><h2 id="switching" tabindex="-1">Switching <a class="header-anchor" href="#switching" aria-label="Permalink to &quot;Switching&quot;">​</a></h2><p>Open the picker with <code>Ctrl+\\</code>. Your <strong>last active persona is remembered</strong> across sessions, so the next launch drops you back where you left off.</p><p>Key properties:</p><ul><li><strong>State is isolated per mode.</strong> A trader conversation stays in trader context. Switching to investor starts a fresh thread with investor&#39;s tools and prompt.</li><li><strong>Mid-lesson safety.</strong> If you&#39;re in Learner mode mid-step and switch to another mode, the step session is preserved and resumes on return.</li><li><strong>Tool palette changes with the mode.</strong> Investor gets Screener; Trader gets the Streak and TradingView workflows; Office Mode desks add mailbox delegation and AITradingOffice memory. Tools are scoped by the active workflow.</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Deep dive on each</strong> → <a href="/wiki/guides/learner">Learner Mode</a> · <a href="/wiki/guides/investor">Investor</a> · <a href="/wiki/guides/trader">Trader</a> · <a href="/wiki/guides/portfolio-manager">PMS and Portfolio Workflows</a></li><li><strong>Connect your broker</strong> → <a href="./../getting-started/broker-setup">Broker Setup</a> — so broker-aware workflows can reach your account</li><li><strong>Configure the browser</strong> → <a href="./../getting-started/browser-setup">Browser Setup</a> — for TradingView, Screener.in, and broker-browser workflows</li></ul><div class="danger custom-block"><p class="custom-block-title">Not financial advice</p><p>Persona outputs are educational and analytical. Nothing <code>tradecli</code> says constitutes a recommendation to buy, sell, or hold any security. Verify against primary sources before trading real capital.</p></div>',14)])])}const f=t(s,[["render",n]]);export{g as __pageData,f as default};
